# Python code generated by the AI model
#!/usr/bin/env python3
"""
4h_PriceAction_VWAP_Pullback_1dTrend
Hypothesis: 4-hour VWAP pullback strategy aligned with daily trend. Enters long when price pulls back to VWAP in an uptrend (price > daily EMA50), and short when price pulls back to VWAP in a downtrend (price < daily EMA50). Uses volume-weighted average price (VWAP) as dynamic support/resistance and daily EMA50 for trend filter. Designed to work in both bull and bear markets by following the higher timeframe trend. Target: 20-40 trades per year.
"""

name = "4h_PriceAction_VWAP_Pullback_1dTrend"
timeframe = "4h"
leverage = 1.0

import numpy as np
import pandas as pd
from mtf_data import get_htf_data, align_htf_to_ltf

def generate_signals(prices):
    n = len(prices)
    if n < 50:
        return np.zeros(n)
    
    high = prices['high'].values
    low = prices['low'].values
    close = prices['close'].values
    volume = prices['volume'].values
    
    # Daily EMA50 for trend filter
    df_1d = get_htf_data(prices, '1d')
    close_1d = df_1d['close'].values
    ema_50_1d = np.full(len(close_1d), np.nan)
    if len(close_1d) >= 50:
        ema_50_1d[49] = np.mean(close_1d[:50])
        alpha = 2 / (50 + 1)
        for i in range(50, len(close_1d)):
            ema_50_1d[i] = alpha * close_1d[i] + (1 - alpha) * ema_50_1d[i-1]
    ema_50_1d_aligned = align_htf_to_ltf(prices, df_1d, ema_50_1d)
    
    # VWAP calculation (typical price * volume) cumulative
    typical_price = (high + low + close) / 3.0
    vwap_num = np.cumsum(typical_price * volume)
    vwap_den = np.cumsum(volume)
    vwap = np.divide(vwap_num, vwap_den, out=np.full_like(vwap_num, np.nan), where=vwap_den!=0)
    
    signals = np.zeros(n)
    position = 0  # 0: flat, 1: long, -1: short
    
    start_idx = 50  # warmup for daily EMA
    
    for i in range(start_idx, n):
        if np.isnan(ema_50_1d_aligned[i]) or np.isnan(vwap[i]):
            if position != 0:
                signals[i] = 0.0
                position = 0
            continue
        
        if position == 0:
            # Long: price pulls back to VWAP in uptrend (close crosses above VWAP and price > daily EMA50)
            if close[i] > vwap[i] and close[i-1] <= vwap[i-1] and close[i] > ema_50_1d_aligned[i]:
                signals[i] = 0.25
                position = 1
            # Short: price pulls back to VWAP in downtrend (close crosses below VWAP and price < daily EMA50)
            elif close[i] < vwap[i] and close[i-1] >= vwap[i-1] and close[i] < ema_50_1d_aligned[i]:
                signals[i] = -0.25
                position = -1
        elif position == 1:
            # Exit long: price breaks below VWAP or trend changes
            if close[i] < vwap[i] or close[i] < ema_50_1d_aligned[i]:
                signals[i] = 0.0
                position = 0
            else:
                signals[i] = 0.25
        elif position == -1:
            # Exit short: price breaks above VWAP or trend changes
            if close[i] > vwap[i] or close[i] > ema_50_1d_aligned[i]:
                signals[i] = 0.0
                position = 0
            else:
                signals[i] = -0.25
    
    return signals